previewCss:
.darma-loader-uiverse-candy-pulse-beads {
  flex-direction: row;
  display: flex;
  align-items: center;
  justify-content: center;
}

.darma-loader-uiverse-candy-pulse-beads__circle {
width: 20px;
height: 20px;
background-color: var(--loader-color, #8bc6ec);
background-image: linear-gradient(135deg, var(--loader-color, #8bc6ec) 0%, var(--loader-secondary-color, #9599e2) 100%);
border-radius: 50%;
margin-right: 1rem;
animation: darma-loader-uiverse-candy-pulse-beads-pulse 1.2s ease-in-out infinite;
}

.darma-loader-uiverse-candy-pulse-beads__circle:nth-child(2) {
animation-delay: 0.2s;
background-color: #4158D0;
background-image: linear-gradient(43deg, #4158D0 0%, #C850C0 46%, #FFCC70 100%);
}

.darma-loader-uiverse-candy-pulse-beads__circle:nth-child(3) {
animation-delay: 0.4s;
background-color: #0093E9;
background-image: linear-gradient(160deg, #0093E9 0%, #80D0C7 100%);
}

.darma-loader-uiverse-candy-pulse-beads__circle:nth-child(4) {
animation-delay: 0.6s;
background-color: #8EC5FC;
background-image: linear-gradient(62deg, #8EC5FC 0%, #E0C3FC 100%);
}

.darma-loader-uiverse-candy-pulse-beads__circle:nth-child(5) {
animation-delay: 0.8s;
background-color: #00DBDE;
background-image: linear-gradient(90deg, #00DBDE 0%, #FC00FF 100%);
}

@keyframes darma-loader-uiverse-candy-pulse-beads-pulse {
0% {
transform: scale(0.8);
opacity: 0.7;
}

50% {
transform: scale(1);
opacity: 1;
}

100% {
transform: scale(0.8);
opacity: 0.7;
}
}

